@namespace Lumeo

@{
    var context = new MenubarContext(_openMenuId, EventCallback.Factory.Create<string?>(this, SetOpenMenuId), _openMenuId is not null, _menuIds, RegisterMenuId, NavigateMenus);
}

<CascadingValue Value="context" IsFixed="false">
    <div role="menubar" class="@CssClass" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
</CascadingValue>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string? _openMenuId;
    private readonly List<string> _menuIds = [];

    private string CssClass => $"flex h-9 items-center space-x-1 rounded-md border border-border/40 bg-background p-1 shadow-sm {Class}".Trim();

    private void SetOpenMenuId(string? menuId)
    {
        _openMenuId = menuId;
        StateHasChanged();
    }

    private void RegisterMenuId(string menuId)
    {
        if (!_menuIds.Contains(menuId))
        {
            _menuIds.Add(menuId);
            StateHasChanged();
        }
    }

    private void NavigateMenus(int direction)
    {
        if (_menuIds.Count == 0) return;
        if (_openMenuId is null)
        {
            _openMenuId = direction > 0 ? _menuIds[0] : _menuIds[^1];
        }
        else
        {
            var currentIndex = _menuIds.IndexOf(_openMenuId);
            if (currentIndex < 0) return;
            var nextIndex = (currentIndex + direction + _menuIds.Count) % _menuIds.Count;
            _openMenuId = _menuIds[nextIndex];
        }
        StateHasChanged();
    }

    public record MenubarContext(
        string? OpenMenuId,
        EventCallback<string?> SetOpenMenuId,
        bool AnyOpen,
        List<string> MenuIds,
        Action<string> RegisterMenuId,
        Action<int> NavigateMenus);
}

@namespace Lumeo
@implements IAsyncDisposable

@if (Context.OpenMenuId == MenuContext.MenuId)
{
    <div id="@_contentId" class="@CssClass" @onkeydown="HandleKeyDown" tabindex="-1" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
}

@inject IComponentInteropService Interop

@code {
    [CascadingParameter] public Menubar.MenubarContext Context { get; set; } = default!;
    [CascadingParameter] public MenubarMenu.MenubarMenuContext MenuContext { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _contentId = LumeoIds.New("menubar-content");
    private bool _registered;

    private string CssClass => $"fixed z-50 min-w-[12rem] overflow-hidden rounded-md border border-border/40 bg-popover p-1 text-popover-foreground shadow-lg animate-fade-in {Class}".Trim();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (Context.OpenMenuId == MenuContext.MenuId && !_registered)
        {
            await Interop.PositionFixed(_contentId, MenuContext.WrapperId, "start");
            await Interop.RegisterClickOutside(_contentId, null, async () =>
            {
                await Context.SetOpenMenuId.InvokeAsync(null);
                await InvokeAsync(StateHasChanged);
            });
            _registered = true;
        }
        else if (Context.OpenMenuId != MenuContext.MenuId && _registered)
        {
            await Cleanup();
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Escape")
        {
            await Context.SetOpenMenuId.InvokeAsync(null);
        }
    }

    private async Task Cleanup()
    {
        try { await Interop.UnpositionFixed(_contentId); } catch (JSDisconnectedException) { }
        try { await Interop.UnregisterClickOutside(_contentId); } catch (JSDisconnectedException) { }
        _registered = false;
    }

    public async ValueTask DisposeAsync()
    {
        if (_registered) await Cleanup();
    }
}

