@namespace Lumeo

@{
    var subContext = new MenubarSubContext(
        _open,
        EventCallback.Factory.Create<bool>(this, SetOpen),
        _wrapperId,
        _triggerId,
        _contentId,
        EventCallback.Factory.Create(this, CloseTree),
        ScheduleClose,
        CancelClose);
}

<CascadingValue Value="subContext" IsFixed="false">
    <div id="@_wrapperId" class="relative" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
</CascadingValue>

@code {
    [CascadingParameter] public Menubar.MenubarContext? RootContext { get; set; }
    [CascadingParameter] public MenubarSubContext? ParentSubContext { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _open;
    private readonly string _wrapperId = LumeoIds.New("menubar-sub");
    internal readonly string _triggerId = LumeoIds.New("menubar-sub-trigger");
    internal readonly string _contentId = LumeoIds.New("menubar-sub-content");

    private CancellationTokenSource? _closeCts;

    private async Task SetOpen(bool value)
    {
        if (_open == value) return;
        _open = value;
        await InvokeAsync(StateHasChanged);
    }

    private async Task CloseTree()
    {
        await SetOpen(false);
        if (ParentSubContext is not null)
        {
            await ParentSubContext.CloseTree.InvokeAsync();
        }
        else if (RootContext is not null)
        {
            await RootContext.SetOpenMenuId.InvokeAsync(null);
        }
    }

    private void CancelClose()
    {
        try { _closeCts?.Cancel(); } catch (ObjectDisposedException) { }
        _closeCts?.Dispose();
        _closeCts = null;
    }

    private void ScheduleClose()
    {
        CancelClose();
        _closeCts = new CancellationTokenSource();
        var token = _closeCts.Token;
        _ = Task.Run(async () =>
        {
            try { await Task.Delay(200, token); }
            catch (TaskCanceledException) { return; }
            if (token.IsCancellationRequested) return;
            await InvokeAsync(async () => await SetOpen(false));
        });
    }

    public record MenubarSubContext(
        bool IsOpen,
        EventCallback<bool> SetOpen,
        string WrapperId,
        string TriggerId,
        string ContentId,
        EventCallback CloseTree,
        Action ScheduleClose,
        Action CancelClose);
}

@namespace Lumeo
@implements IAsyncDisposable

@if (SubContext.IsOpen)
{
    <div id="@SubContext.ContentId"
         role="menu"
         aria-orientation="vertical"
         class="@CssClass"
         tabindex="-1"
         @onkeydown="HandleKeyDown"
         @onmouseenter="HandleMouseEnter"
         @onmouseleave="HandleMouseLeave"
         @onmousedown:stopPropagation="true"
         @ontouchstart:stopPropagation="true"
         @attributes="AdditionalAttributes">
        @ChildContent
    </div>
}

@inject IComponentInteropService Interop

@code {
    [CascadingParameter] public MenubarSub.MenubarSubContext SubContext { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _positioned;
    private int _focusedIndex = -1;

    private string CssClass => $"fixed z-50 min-w-[12rem] overflow-hidden rounded-md border border-border/40 bg-popover p-1 text-popover-foreground shadow-lg animate-fade-in {Class}".Trim();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (SubContext.IsOpen && !_positioned)
        {
            await PositionWithFlip();
            _positioned = true;
            _focusedIndex = -1;
        }
        else if (!SubContext.IsOpen && _positioned)
        {
            await Cleanup();
        }
    }

    private async Task PositionWithFlip()
    {
        var side = "right";
        try
        {
            var triggerRect = await Interop.GetElementRect(SubContext.TriggerId);
            var viewport = await Interop.GetViewportSize();
            if (triggerRect is not null && triggerRect.X + triggerRect.Width + 200 > viewport.Width)
            {
                side = "left";
            }
        }
        catch (JSDisconnectedException) { }

        await Interop.PositionFixed(SubContext.ContentId, SubContext.TriggerId, "start", false, side);
    }

    private Task HandleMouseEnter()
    {
        SubContext.CancelClose();
        return Task.CompletedTask;
    }

    private void HandleMouseLeave()
    {
        SubContext.ScheduleClose();
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "Escape":
                await SubContext.CloseTree.InvokeAsync();
                break;
            case "ArrowLeft":
                SubContext.CancelClose();
                await SubContext.SetOpen.InvokeAsync(false);
                try { await Interop.FocusElement(SubContext.TriggerId); } catch (JSDisconnectedException) { }
                break;
            case "ArrowDown":
                {
                    var count = await Interop.GetMenuItemCount(SubContext.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = (_focusedIndex + 1) % count;
                        await Interop.FocusMenuItemByIndex(SubContext.ContentId, _focusedIndex);
                    }
                    break;
                }
            case "ArrowUp":
                {
                    var count = await Interop.GetMenuItemCount(SubContext.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = _focusedIndex <= 0 ? count - 1 : _focusedIndex - 1;
                        await Interop.FocusMenuItemByIndex(SubContext.ContentId, _focusedIndex);
                    }
                    break;
                }
            case "Home":
                {
                    var count = await Interop.GetMenuItemCount(SubContext.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = 0;
                        await Interop.FocusMenuItemByIndex(SubContext.ContentId, _focusedIndex);
                    }
                    break;
                }
            case "End":
                {
                    var count = await Interop.GetMenuItemCount(SubContext.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = count - 1;
                        await Interop.FocusMenuItemByIndex(SubContext.ContentId, _focusedIndex);
                    }
                    break;
                }
        }
    }

    private async Task Cleanup()
    {
        try { await Interop.UnpositionFixed(SubContext.ContentId); } catch (JSDisconnectedException) { }
        _positioned = false;
    }

    public async ValueTask DisposeAsync()
    {
        if (_positioned) await Cleanup();
    }
}

@namespace Lumeo

<button id="@SubContext.TriggerId"
        type="button"
        role="menuitem"
        tabindex="-1"
        class="@CssClass"
        data-state="@(SubContext.IsOpen ? "open" : "closed")"
        aria-haspopup="menu"
        aria-expanded="@SubContext.IsOpen.ToString().ToLower()"
        aria-controls="@SubContext.ContentId"
        disabled="@Disabled"
        @onclick="HandleClick"
        @onmouseenter="HandleMouseEnter"
        @onmouseleave="HandleMouseLeave"
        @onkeydown="HandleKeyDown"
        @attributes="AdditionalAttributes">
    @ChildContent
    <Blazicon Svg="Lucide.ChevronRight" class="ml-auto h-4 w-4" />
</button>

@inject IComponentInteropService Interop

@code {
    [CascadingParameter] public MenubarSub.MenubarSubContext SubContext { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"relative flex w-full cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground focus:bg-accent focus:text-accent-foreground data-[state=open]:bg-accent data-[state=open]:text-accent-foreground disabled:pointer-events-none disabled:opacity-50 disabled:cursor-not-allowed {Class}".Trim();

    private async Task HandleClick()
    {
        if (Disabled) return;
        SubContext.CancelClose();
        await SubContext.SetOpen.InvokeAsync(!SubContext.IsOpen);
    }

    private async Task HandleMouseEnter()
    {
        if (Disabled) return;
        SubContext.CancelClose();
        if (!SubContext.IsOpen)
        {
            await SubContext.SetOpen.InvokeAsync(true);
        }
    }

    private void HandleMouseLeave()
    {
        if (!SubContext.IsOpen) return;
        SubContext.ScheduleClose();
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "ArrowRight":
            case "Enter":
            case " ":
                SubContext.CancelClose();
                if (!SubContext.IsOpen)
                {
                    await SubContext.SetOpen.InvokeAsync(true);
                }
                _ = InvokeAsync(async () =>
                {
                    await Task.Delay(20);
                    try { await Interop.FocusMenuItemByIndex(SubContext.ContentId, 0); }
                    catch (JSDisconnectedException) { }
                });
                break;
        }
    }
}

@namespace Lumeo

<button class="@CssClass" tabindex="@TabIndex" @onclick="HandleClick" @onmouseenter="HandleMouseEnter" @onkeydown="HandleKeyDown" @attributes="AdditionalAttributes">
    @ChildContent
</button>

@code {
    [CascadingParameter] public Menubar.MenubarContext Context { get; set; } = default!;
    [CascadingParameter] public MenubarMenu.MenubarMenuContext MenuContext { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool IsOpen => Context.OpenMenuId == MenuContext.MenuId;

    // Roving tabindex: the active (open) trigger — or the first registered trigger
    // when none is open — gets tabindex=0; all others get tabindex=-1.
    private string TabIndex
    {
        get
        {
            if (IsOpen) return "0";
            if (Context.OpenMenuId is null && Context.MenuIds.Count > 0 && Context.MenuIds[0] == MenuContext.MenuId) return "0";
            return "-1";
        }
    }

    private string CssClass => Cx.Join(
        "flex cursor-default select-none items-center rounded-sm px-3 py-1 text-sm font-medium outline-none",
        Cx.When(IsOpen, "bg-accent text-accent-foreground"),
        Class);

    private async Task HandleClick()
    {
        if (IsOpen)
        {
            await Context.SetOpenMenuId.InvokeAsync(null);
        }
        else
        {
            await Context.SetOpenMenuId.InvokeAsync(MenuContext.MenuId);
        }
    }

    private async Task HandleMouseEnter()
    {
        if (Context.AnyOpen)
        {
            await Context.SetOpenMenuId.InvokeAsync(MenuContext.MenuId);
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "ArrowDown":
            case "Enter":
            case " ":
                if (!IsOpen)
                {
                    await Context.SetOpenMenuId.InvokeAsync(MenuContext.MenuId);
                }
                break;
            case "ArrowLeft":
                Context.NavigateMenus(-1);
                break;
            case "ArrowRight":
                Context.NavigateMenus(1);
                break;
            case "Escape":
                if (IsOpen)
                {
                    await Context.SetOpenMenuId.InvokeAsync(null);
                }
                break;
        }
    }
}
